// MARK: - Secure API Manager

class SecureAPIManager {
    static let shared = SecureAPIManager()
    private let baseURL = "https://api.tradingplatform.com/v1"
    private var apiKey: String = ""
    private var apiSecret: String = ""
    
    private init() {
        loadCredentials()
    }
    
    private func loadCredentials() {
        // Load from Keychain in production
        apiKey = "YOUR_API_KEY"
        apiSecret = "YOUR_API_SECRET"
    }
    
    private func generateSignature(endpoint: String, timestamp: String, body: Data?) -> String {
        let message = "\(timestamp)\(endpoint)\(body?.base64EncodedString() ?? "")"
        let key = SymmetricKey(data: Data(apiSecret.utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: Data(message.utf8), using: key)
        return Data(signature).base64EncodedString()
    }
    
    func request<T: Codable>(endpoint: String, method: String = "GET", body: Codable? = nil) async throws -> T {
        guard let url = URL(string: "\(baseURL)\(endpoint)") else {
            throw URLError(.badURL)
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue(apiKey, forHTTPHeaderField: "X-API-Key")
        
        let timestamp = String(Int(Date().timeIntervalSince1970))
        request.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")
        
        var bodyData: Data? = nil
        if let body = body {
            bodyData = try JSONEncoder().encode(body)
            request.httpBody = bodyData
        }
        
        let signature = generateSignature(endpoint: endpoint, timestamp: timestamp, body: bodyData)
        request.setValue(signature, forHTTPHeaderField: "X-Signature")
        
        let (data, response) = try await URLSession.shared.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw URLError(.badServerResponse)
        }
        
        guard (200...299).contains(httpResponse.statusCode) else {
            throw URLError(.init(rawValue: httpResponse.statusCode))
        }
        
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try decoder.decode(T.self, from: data)
    }
}

// MARK: - Trading Service

class TradingService {
    static let shared = TradingService()
    private let apiManager = SecureAPIManager.shared
    
    func executeOrder(request: OrderRequest) async throws -> Trade {
        let response: APIResponse<Trade> = try await apiManager.request(
            endpoint: "/trades/execute",
            method: "POST",
            body: request
        )
        
        guard let trade = response.data else {
            throw NSError(domain: "TradingService", code: -1, userInfo: [NSLocalizedDescriptionKey: response.error ?? "Unknown error"])
        }
        
        return trade
    }
    
    func getMarketData(symbol: String) async throws -> MarketData {
        let response: APIResponse<MarketData> = try await apiManager.request(
            endpoint: "/market/\(symbol)",
            method: "GET"
        )
        
        guard let data = response.data else {
            throw NSError(domain: "TradingService", code: -1, userInfo: [NSLocalizedDescriptionKey: response.error ?? "Unknown error"])
        }
        
        return data
    }
    
    func getTradeHistory(userId: String) async throws -> [Trade] {
        let response: APIResponse<[Trade]> = try await apiManager.request(
            endpoint: "/trades/history/\(userId)",
            method: "GET"
        )
        
        return response.data ?? []
    }
    
    func cancelOrder(tradeId: String) async throws -> Bool {
        let response: APIResponse<Bool> = try await apiManager.request(
            endpoint: "/trades/cancel/\(tradeId)",
            method: "DELETE"
        )
        
        return response.data ?? false
    }
}

// MARK: - Portfolio Manager

class PortfolioManager: ObservableObject {
    static let shared = PortfolioManager()
    @Published var portfolio: Portfolio?
    @Published var holdings: [Holding] = []
    
    private let apiManager = SecureAPIManager.shared
    private var cancellables = Set<AnyCancellable>()
    
    func loadPortfolio(userId: String) async throws {
        let response: APIResponse<Portfolio> = try await apiManager.request(
            endpoint: "/portfolio/\(userId)",
            method: "GET"
        )
        
        if let portfolio = response.data {
            await MainActor.run {
                self.portfolio = portfolio
                self.holdings = portfolio.holdings
            }
        }
    }
    
    func updateHolding(symbol: String, quantity: Int, price: Double, type: TradeType) {
        guard var portfolio = portfolio else { return }
        
        if let index = portfolio.holdings.firstIndex(where: { $0.symbol == symbol }) {
            var holding = portfolio.holdings[index]
            
            if type == .buy {
                let totalCost = (holding.averagePrice * Double(holding.quantity)) + (price * Double(quantity))
                holding.quantity += quantity
                holding.averagePrice = totalCost / Double(holding.quantity)
                portfolio.cashBalance -= price * Double(quantity)
            } else {
                holding.quantity -= quantity
                portfolio.cashBalance += price * Double(quantity)
                
                if holding.quantity <= 0 {
                    portfolio.holdings.remove(at: index)
                    self.portfolio = portfolio
                    self.holdings = portfolio.holdings
                    return
                }
            }
            
            portfolio.holdings[index] = holding
        } else if type == .buy {
            let newHolding = Holding(
                id: UUID().uuidString,
                symbol: symbol,
                quantity: quantity,
                averagePrice: price,
                currentPrice: price,
                totalValue: price * Double(quantity),
                gainLoss: 0,
                gainLossPercent: 0
            )
            portfolio.holdings.append(newHolding)
            portfolio.cashBalance -= price * Double(quantity)
        }
        
        self.portfolio = portfolio
        self.holdings = portfolio.holdings
    }
    
    func calculatePortfolioValue() -> Double {
        guard let portfolio = portfolio else { return 0 }
        let holdingsValue = holdings.reduce(0) { $0 + $1.totalValue }
        return holdingsValue + portfolio.cashBalance
    }
}

// MARK: - Real-Time Market Data Manager

class MarketDataManager: ObservableObject {
    static let shared = MarketDataManager()
    @Published var stocks: [String: Stock] = [:]
    @Published var marketData: [String: MarketData] = [:]
    
    private var webSocketTask: URLSessionWebSocketTask?
    private var cancellables = Set<AnyCancellable>()
    
    func connectWebSocket() {
        guard let url = URL(string: "wss://api.tradingplatform.com/v1/stream") else { return }
        
        let session = URLSession(configuration: .default)
        webSocketTask = session.webSocketTask(with: url)
        webSocketTask?.resume()
        
        receiveMessage()
    }
    
    private func receiveMessage() {
        webSocketTask?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .string(let text):
                    self?.handleMessage(text)
                case .data(let data):
                    self?.handleData(data)
                @unknown default:
                    break
                }
                self?.receiveMessage()
            case .failure(let error):
                print("WebSocket error: \(error)")
            }
        }
    }
    
    private func handleMessage(_ message: String) {
        guard let data = message.data(using: .utf8) else { return }
        handleData(data)
    }
    
    private func handleData(_ data: Data) {
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        
        if let marketData = try? decoder.decode(MarketData.self, from: data) {
            DispatchQueue.main.async {
                self.marketData[marketData.symbol] = marketData
                self.updateStockPrice(symbol: marketData.symbol, price: marketData.price)
            }
        }
    }
    
    private func updateStockPrice(symbol: String, price: Double) {
        if var stock = stocks[symbol] {
            let oldPrice = stock.currentPrice
            stock.currentPrice = price
            stock.changePercent = ((price - oldPrice) / oldPrice) * 100
            stock.lastUpdated = Date()
            stocks[symbol] = stock
        }
    }
    
    func subscribe(symbols: [String]) {
        let subscribeMessage = ["action": "subscribe", "symbols": symbols] as [String : Any]
        if let data = try? JSONSerialization.data(withJSONObject: subscribeMessage),
           let message = String(data: data, encoding: .utf8) {
            webSocketTask?.send(.string(message)) { error in
                if let error = error {
                    print("Subscribe error: \(error)")
                }
            }
        }
    }
    
    func disconnect() {
        webSocketTask?.cancel(with: .goingAway, reason: nil)
    }
}

// MARK: - Trading View Model

class TradingViewModel: ObservableObject {
    @Published var selectedStock: Stock?
    @Published var quantity: Int = 1
    @Published var orderType: OrderType = .market
    @Published var limitPrice: Double?
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var successMessage: String?
    @Published var recentTrades: [Trade] = []
    
    private let tradingService = TradingService.shared
    private let portfolioManager = PortfolioManager.shared
    private var cancellables = Set<AnyCancellable>()
    
    func executeTrade(type: TradeType) async {
        guard let stock = selectedStock else { return }
        
        await MainActor.run {
            isLoading = true
            errorMessage = nil
            successMessage = nil
        }
        
        do {
            let orderRequest = OrderRequest(
                symbol: stock.symbol,
                type: type,
                quantity: quantity,
                orderType: orderType,
                limitPrice: limitPrice
            )
            
            let trade = try await tradingService.executeOrder(request: orderRequest)
            
            await MainActor.run {
                if trade.status == .executed {
                    portfolioManager.updateHolding(
                        symbol: stock.symbol,
                        quantity: quantity,
                        price: trade.price,
                        type: type
                    )
                    successMessage = "\(type.rawValue.capitalized) order executed: \(quantity) shares of \(stock.symbol) at $\(trade.price)"
                    recentTrades.insert(trade, at: 0)
                } else {
                    errorMessage = "Order failed to execute"
                }
                isLoading = false
            }
        } catch {
            await MainActor.run {
                errorMessage = "Trade execution failed: \(error.localizedDescription)"
                isLoading = false
            }
        }
    }
    
    func loadTradeHistory(userId: String) async {
        do {
            let trades = try await tradingService.getTradeHistory(userId: userId)
            await MainActor.run {
                recentTrades = trades
            }
        } catch {
            await MainActor.run {
                errorMessage = "Failed to load trade history"
            }
        }
    }
    
    func calculateOrderValue() -> Double {
        guard let stock = selectedStock else { return 0 }
        let price = orderType == .limit ? (limitPrice ?? stock.currentPrice) : stock.currentPrice
        return price * Double(quantity)
    }
    
    func validateOrder(type: TradeType) -> Bool {
        guard let portfolio = portfolioManager.portfolio else { return false }
        
        if type == .buy {
            let orderValue = calculateOrderValue()
            return portfolio.cashBalance >= orderValue
        } else {
            guard let stock = selectedStock,
                  let holding = portfolio.holdings.first(where: { $0.symbol == stock.symbol }) else {
                return false
            }
            return holding.quantity >= quantity
        }
    }
}

